import{_ as t,o as d,c as o,ak as r}from"./chunks/framework.Dga8WbZz.js";const m=JSON.parse('{"title":"IOperation to Expression Mapping","description":"","frontmatter":{},"headers":[],"relativePath":"advanced/ioperation-mapping.md","filePath":"advanced/ioperation-mapping.md"}'),a={name:"advanced/ioperation-mapping.md"};function n(c,e,i,s,p,l){return d(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="ioperation-to-expression-mapping" tabindex="-1">IOperation to Expression Mapping <a class="header-anchor" href="#ioperation-to-expression-mapping" aria-label="Permalink to “IOperation to Expression Mapping”">​</a></h1><p>Reference table mapping Roslyn <code>IOperation</code> types to <code>System.Linq.Expressions.Expression</code> factory methods, as implemented in <code>ExpressionTreeEmitter</code>.</p><p><strong>Roslyn version</strong>: Microsoft.CodeAnalysis.CSharp 5.0.0 <strong>Target</strong>: <code>System.Linq.Expressions</code> (netstandard2.0+)</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to “Overview”">​</a></h2><p><code>ExpressionTreeEmitter</code> walks the Roslyn <code>IOperation</code> tree for a member body and emits imperative C# code that builds the equivalent <code>Expression&lt;TDelegate&gt;</code> using factory methods. It receives the <strong>original syntax</strong> and <strong>original semantic model</strong> -- no syntax preprocessing is required. Transparent syntax wrappers (<code>checked()</code>, <code>unchecked()</code>, parenthesized, null-forgiving <code>!</code>) are unwrapped before <code>GetOperation</code> is called.</p><h2 id="legend" tabindex="-1">Legend <a class="header-anchor" href="#legend" aria-label="Permalink to “Legend”">​</a></h2><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td>Implemented</td><td>Handled in <code>ExpressionTreeEmitter.EmitOperation()</code> dispatch</td></tr><tr><td>Not yet implemented</td><td>Has a clear path to implementation; currently falls through to <code>EmitUnsupported()</code></td></tr><tr><td>N/A</td><td>No <code>Expression.*</code> equivalent exists; not applicable to expression trees</td></tr></tbody></table><p>Unrecognized operations fall through to <code>EmitUnsupported()</code> which emits <code>Expression.Default(typeof(T))</code> and reports diagnostic <code>EXP0008</code>.</p><hr><h2 id="core-expression-operations" tabindex="-1">Core Expression Operations <a class="header-anchor" href="#core-expression-operations" aria-label="Permalink to “Core Expression Operations”">​</a></h2><table tabindex="0"><thead><tr><th>IOperation</th><th>Expression Factory</th><th>Status</th><th>Notes</th></tr></thead><tbody><tr><td><code>ILiteralOperation</code></td><td><code>Expression.Constant(value, typeof(T))</code></td><td>Implemented</td><td>Special formatting for <code>float.NaN</code>, <code>double.PositiveInfinity</code>, char/string escaping, numeric suffixes.</td></tr><tr><td><code>IParameterReferenceOperation</code></td><td><code>Expression.Parameter(typeof(T), &quot;name&quot;)</code></td><td>Implemented</td><td>Looks up pre-created <code>ParameterExpression</code> from <code>_symbolToVar</code> cache.</td></tr><tr><td><code>IInstanceReferenceOperation</code></td><td><code>ParameterExpression</code> for <code>@this</code></td><td>Implemented</td><td>Returns the <code>_thisVarName</code> parameter.</td></tr><tr><td><code>ILocalReferenceOperation</code></td><td><code>Expression.Variable(typeof(T), &quot;name&quot;)</code></td><td>Implemented</td><td>Looks up from <code>_localToVar</code> cache, populated by <code>EmitBlock</code> variable declarations.</td></tr><tr><td><code>IParenthesizedOperation</code></td><td><em>(transparent)</em></td><td>Implemented</td><td>Unwrapped: recursively emits the inner <code>Operand</code>.</td></tr></tbody></table><h2 id="member-access" tabindex="-1">Member Access <a class="header-anchor" href="#member-access" aria-label="Permalink to “Member Access”">​</a></h2><table tabindex="0"><thead><tr><th>IOperation</th><th>Expression Factory</th><th>Status</th><th>Notes</th></tr></thead><tbody><tr><td><code>IPropertyReferenceOperation</code></td><td><code>Expression.Property(instance, PropertyInfo)</code></td><td>Implemented</td><td>Cached via <code>ReflectionFieldCache.EnsurePropertyInfo()</code>.</td></tr><tr><td><code>IFieldReferenceOperation</code></td><td><code>Expression.Field(instance, FieldInfo)</code></td><td>Implemented</td><td>Cached via <code>ReflectionFieldCache.EnsureFieldInfo()</code>.</td></tr><tr><td><code>IArrayElementReferenceOperation</code></td><td><code>Expression.ArrayIndex(array, index)</code> / <code>Expression.ArrayAccess(array, indices)</code></td><td>Implemented</td><td>Single index uses <code>ArrayIndex</code>; multiple uses <code>ArrayAccess</code>.</td></tr><tr><td><code>IEventReferenceOperation</code></td><td>--</td><td>N/A</td><td>Events cannot be represented in expression trees.</td></tr></tbody></table><h2 id="invocation-and-creation" tabindex="-1">Invocation and Creation <a class="header-anchor" href="#invocation-and-creation" aria-label="Permalink to “Invocation and Creation”">​</a></h2><table tabindex="0"><thead><tr><th>IOperation</th><th>Expression Factory</th><th>Status</th><th>Notes</th></tr></thead><tbody><tr><td><code>IInvocationOperation</code></td><td><code>Expression.Call(instance, MethodInfo, args)</code></td><td>Implemented</td><td>Static/instance dispatch. Generic methods resolved via <code>MakeGenericMethod()</code>. Enum method expansion to ternary chains.</td></tr><tr><td><code>IObjectCreationOperation</code></td><td><code>Expression.New(ConstructorInfo, args)</code></td><td>Implemented</td><td>With member initializer: <code>Expression.MemberInit</code>. With collection initializer: <code>Expression.ListInit</code> via <code>Expression.ElementInit</code>.</td></tr><tr><td><code>IAnonymousObjectCreationOperation</code></td><td><code>Expression.New(ctor, args, members)</code></td><td>Implemented (interceptor path)</td><td>Uses inline runtime reflection via generic type parameters (e.g., <code>typeof(TResult).GetConstructors()[0]</code>). Nested anonymous types fall back to EXP0008.</td></tr><tr><td><code>IDelegateCreationOperation</code></td><td><em>(transparent)</em></td><td>Implemented</td><td>Emits its <code>Target</code> operation directly.</td></tr><tr><td><code>IArrayCreationOperation</code></td><td><code>Expression.NewArrayInit</code> / <code>Expression.NewArrayBounds</code></td><td>Implemented</td><td>With initializer: <code>NewArrayInit</code>; without: <code>NewArrayBounds</code>.</td></tr></tbody></table><h2 id="operators" tabindex="-1">Operators <a class="header-anchor" href="#operators" aria-label="Permalink to “Operators”">​</a></h2><table tabindex="0"><thead><tr><th>IOperation</th><th>Expression Factory</th><th>Status</th><th>Notes</th></tr></thead><tbody><tr><td><code>IBinaryOperation</code></td><td><code>Expression.MakeBinary(ExpressionType, left, right)</code></td><td>Implemented</td><td>Maps <code>BinaryOperatorKind</code> to <code>ExpressionType</code>. Supports checked variants (<code>AddChecked</code>, <code>SubtractChecked</code>, <code>MultiplyChecked</code>) when <code>IsChecked</code> is true. Unrecognized operators report <code>EXP0009</code> diagnostic.</td></tr><tr><td><code>IUnaryOperation</code></td><td><code>Expression.MakeUnary(ExpressionType, operand, type)</code></td><td>Implemented</td><td>Supports <code>NegateChecked</code> when <code>IsChecked</code> is true. Unrecognized operators report <code>EXP0009</code>.</td></tr><tr><td><code>IIncrementOrDecrementOperation</code></td><td><code>Expression.Assign(target, MakeBinary(Add/Sub, target, 1))</code></td><td>Implemented</td><td><code>++</code>/<code>--</code> emitted as assign + binary. Supports checked variants.</td></tr><tr><td><code>ICompoundAssignmentOperation</code></td><td><code>Expression.Assign(target, MakeBinary(op, target, value))</code></td><td>Implemented</td><td><code>+=</code>, <code>-=</code>, etc. emitted as assign + binary. Supports checked variants.</td></tr></tbody></table><h3 id="binary-operator-kind-mapping" tabindex="-1">Binary Operator Kind Mapping <a class="header-anchor" href="#binary-operator-kind-mapping" aria-label="Permalink to “Binary Operator Kind Mapping”">​</a></h3><table tabindex="0"><thead><tr><th><code>BinaryOperatorKind</code></th><th><code>ExpressionType</code></th><th>Checked variant</th></tr></thead><tbody><tr><td><code>Add</code></td><td><code>Add</code></td><td><code>AddChecked</code></td></tr><tr><td><code>Subtract</code></td><td><code>Subtract</code></td><td><code>SubtractChecked</code></td></tr><tr><td><code>Multiply</code></td><td><code>Multiply</code></td><td><code>MultiplyChecked</code></td></tr><tr><td><code>Divide</code></td><td><code>Divide</code></td><td>--</td></tr><tr><td><code>Remainder</code></td><td><code>Modulo</code></td><td>--</td></tr><tr><td><code>LeftShift</code></td><td><code>LeftShift</code></td><td>--</td></tr><tr><td><code>RightShift</code></td><td><code>RightShift</code></td><td>--</td></tr><tr><td><code>And</code> (bitwise)</td><td><code>And</code></td><td>--</td></tr><tr><td><code>Or</code> (bitwise)</td><td><code>Or</code></td><td>--</td></tr><tr><td><code>ExclusiveOr</code></td><td><code>ExclusiveOr</code></td><td>--</td></tr><tr><td><code>ConditionalAnd</code> (<code>&amp;&amp;</code>)</td><td><code>AndAlso</code></td><td>--</td></tr><tr><td><code>ConditionalOr</code> (<code>||</code>)</td><td><code>OrElse</code></td><td>--</td></tr><tr><td><code>Equals</code></td><td><code>Equal</code></td><td>--</td></tr><tr><td><code>NotEquals</code></td><td><code>NotEqual</code></td><td>--</td></tr><tr><td><code>LessThan</code></td><td><code>LessThan</code></td><td>--</td></tr><tr><td><code>LessThanOrEqual</code></td><td><code>LessThanOrEqual</code></td><td>--</td></tr><tr><td><code>GreaterThan</code></td><td><code>GreaterThan</code></td><td>--</td></tr><tr><td><code>GreaterThanOrEqual</code></td><td><code>GreaterThanOrEqual</code></td><td>--</td></tr><tr><td><em>(unrecognized)</em></td><td>--</td><td>Reports <code>EXP0009</code> diagnostic</td></tr></tbody></table><h3 id="unary-operator-kind-mapping" tabindex="-1">Unary Operator Kind Mapping <a class="header-anchor" href="#unary-operator-kind-mapping" aria-label="Permalink to “Unary Operator Kind Mapping”">​</a></h3><table tabindex="0"><thead><tr><th><code>UnaryOperatorKind</code></th><th><code>ExpressionType</code></th><th>Checked variant</th></tr></thead><tbody><tr><td><code>BitwiseNegation</code> (<code>~</code>)</td><td><code>OnesComplement</code></td><td>--</td></tr><tr><td><code>Not</code> (<code>!</code>)</td><td><code>Not</code></td><td>--</td></tr><tr><td><code>Plus</code> (<code>+</code>)</td><td><code>UnaryPlus</code></td><td>--</td></tr><tr><td><code>Minus</code> (<code>-</code>)</td><td><code>Negate</code></td><td><code>NegateChecked</code></td></tr><tr><td><em>(unrecognized)</em></td><td>--</td><td>Reports <code>EXP0009</code> diagnostic</td></tr></tbody></table><h2 id="type-operations" tabindex="-1">Type Operations <a class="header-anchor" href="#type-operations" aria-label="Permalink to “Type Operations”">​</a></h2><table tabindex="0"><thead><tr><th>IOperation</th><th>Expression Factory</th><th>Status</th><th>Notes</th></tr></thead><tbody><tr><td><code>IConversionOperation</code></td><td><code>Expression.Convert(expr, typeof(T))</code></td><td>Implemented</td><td>Identity conversions skipped. <code>ConvertChecked</code> emitted when <code>IsChecked</code> is true. User-defined operators pass <code>MethodInfo</code>.</td></tr><tr><td><code>ITypeOfOperation</code></td><td><code>Expression.Constant(typeof(T), typeof(Type))</code></td><td>Implemented</td><td></td></tr><tr><td><code>IDefaultValueOperation</code></td><td><code>Expression.Default(typeof(T))</code></td><td>Implemented</td><td></td></tr><tr><td><code>IIsTypeOperation</code></td><td><code>Expression.TypeIs(expr, typeof(T))</code></td><td>Implemented</td><td>Simple <code>is Type</code> check.</td></tr></tbody></table><h2 id="conditional-and-null-operations" tabindex="-1">Conditional and Null Operations <a class="header-anchor" href="#conditional-and-null-operations" aria-label="Permalink to “Conditional and Null Operations”">​</a></h2><table tabindex="0"><thead><tr><th>IOperation</th><th>Expression Factory</th><th>Status</th><th>Notes</th></tr></thead><tbody><tr><td><code>IConditionalOperation</code></td><td><code>Expression.Condition</code> / <code>Expression.IfThen</code> / <code>Expression.IfThenElse</code></td><td>Implemented</td><td>Ternary <code>? :</code> uses <code>Condition</code>. Statement-form if/else uses <code>IfThen</code>/<code>IfThenElse</code> (void-typed).</td></tr><tr><td><code>IConditionalAccessOperation</code></td><td><code>Expression.Condition(notNullCheck, whenNotNull, default)</code></td><td>Implemented</td><td><code>?.</code> operator with receiver stack for chained access. Handles <code>Nullable&lt;T&gt;</code> <code>.Value</code> injection.</td></tr><tr><td><code>IConditionalAccessInstanceOperation</code></td><td><em>(resolved to receiver)</em></td><td>Implemented</td><td>Pops from receiver stack during conditional access processing.</td></tr><tr><td><code>ICoalesceOperation</code></td><td><code>Expression.Coalesce(left, right)</code></td><td>Implemented</td><td><code>??</code> operator.</td></tr></tbody></table><h2 id="pattern-matching" tabindex="-1">Pattern Matching <a class="header-anchor" href="#pattern-matching" aria-label="Permalink to “Pattern Matching”">​</a></h2><table tabindex="0"><thead><tr><th>IOperation</th><th>Expression Factory</th><th>Status</th><th>Notes</th></tr></thead><tbody><tr><td><code>IIsPatternOperation</code></td><td>Dispatches to pattern-specific emission</td><td>Implemented</td><td>Full pattern matching dispatch.</td></tr><tr><td><code>IConstantPatternOperation</code></td><td><code>Expression.Equal(expr, Expression.Constant(value))</code></td><td>Implemented</td><td></td></tr><tr><td><code>ITypePatternOperation</code></td><td><code>Expression.TypeIs(expr, typeof(T))</code></td><td>Implemented</td><td></td></tr><tr><td><code>IDeclarationPatternOperation</code></td><td><code>Expression.TypeIs</code> / cast substitution in switch arms</td><td>Implemented</td><td>Named declarations in switch arms substitute with <code>Expression.Convert</code>.</td></tr><tr><td><code>IRelationalPatternOperation</code></td><td><code>Expression.MakeBinary(op, expr, constant)</code></td><td>Implemented</td><td>Unrecognized operators report <code>EXP0009</code>.</td></tr><tr><td><code>INegatedPatternOperation</code></td><td><code>Expression.Not(innerPatternExpr)</code></td><td>Implemented</td><td></td></tr><tr><td><code>IBinaryPatternOperation</code></td><td><code>Expression.AndAlso</code> / <code>Expression.OrElse</code></td><td>Implemented</td><td></td></tr><tr><td><code>IRecursivePatternOperation</code></td><td>Null-check + type guard + property/positional conditions</td><td>Implemented</td><td>Positional patterns resolve via <code>Deconstruct</code> parameters or <code>ItemN</code> fields.</td></tr><tr><td><code>IDiscardPatternOperation</code></td><td><code>Expression.Constant(true)</code></td><td>Implemented</td><td></td></tr><tr><td><code>IListPatternOperation</code></td><td>Count/Length check + indexed element pattern checks</td><td>Implemented</td><td>Fixed-length and slice patterns. Requires <code>Count</code>/<code>Length</code> property and indexer on operand type.</td></tr><tr><td><code>ISlicePatternOperation</code></td><td><em>(handled within list pattern)</em></td><td>Implemented</td><td>Slice (<code>..</code>) adjusts index calculations for elements after the slice.</td></tr></tbody></table><h2 id="switch-expressions" tabindex="-1">Switch Expressions <a class="header-anchor" href="#switch-expressions" aria-label="Permalink to “Switch Expressions”">​</a></h2><table tabindex="0"><thead><tr><th>IOperation</th><th>Expression Factory</th><th>Status</th><th>Notes</th></tr></thead><tbody><tr><td><code>ISwitchExpressionOperation</code></td><td>Nested <code>Expression.Condition</code> chain</td><td>Implemented</td><td>Arms processed in reverse. Discard arm becomes innermost fallback. Declaration patterns in arms substitute with cast.</td></tr></tbody></table><h2 id="tuple-operations" tabindex="-1">Tuple Operations <a class="header-anchor" href="#tuple-operations" aria-label="Permalink to “Tuple Operations”">​</a></h2><table tabindex="0"><thead><tr><th>IOperation</th><th>Expression Factory</th><th>Status</th><th>Notes</th></tr></thead><tbody><tr><td><code>ITupleOperation</code></td><td><code>Expression.New(ValueTuple&lt;...&gt; ctor, elements)</code></td><td>Implemented</td><td>Handles 1-7 elements directly. 8+ elements use nested <code>ValueTuple</code> for <code>Rest</code> argument.</td></tr><tr><td><code>ITupleBinaryOperation</code></td><td>Element-wise <code>Equal</code> + <code>AndAlso</code> / <code>Not</code></td><td>Implemented</td><td><code>(a, b) == (c, d)</code> becomes <code>AndAlso(Equal(a.Item1, c.Item1), Equal(a.Item2, c.Item2))</code>. <code>!=</code> wraps in <code>Not</code>.</td></tr></tbody></table><h2 id="index-and-range" tabindex="-1">Index and Range <a class="header-anchor" href="#index-and-range" aria-label="Permalink to “Index and Range”">​</a></h2><table tabindex="0"><thead><tr><th>IOperation</th><th>Expression Factory</th><th>Status</th><th>Notes</th></tr></thead><tbody><tr><td><code>IUnaryOperation</code> (Hat)</td><td><code>Expression.New(Index ctor, value, true)</code></td><td>Implemented</td><td><code>^n</code> becomes <code>new Index(n, fromEnd: true)</code>.</td></tr><tr><td><code>IRangeOperation</code></td><td><code>Expression.New(Range ctor, start, end)</code></td><td>Implemented</td><td><code>a..b</code> becomes <code>new Range(start, end)</code>. Implicit start/end produce <code>new Index(0, false)</code> / <code>new Index(0, true)</code>. Operand <code>int</code> to <code>Index</code> conversions handled by <code>EmitConversion</code>.</td></tr></tbody></table><h2 id="collection-expressions" tabindex="-1">Collection Expressions <a class="header-anchor" href="#collection-expressions" aria-label="Permalink to “Collection Expressions”">​</a></h2><table tabindex="0"><thead><tr><th>IOperation</th><th>Expression Factory</th><th>Status</th><th>Notes</th></tr></thead><tbody><tr><td><code>ICollectionExpressionOperation</code></td><td><code>Expression.NewArrayInit</code> / <code>Expression.ListInit</code></td><td>Implemented</td><td>C# 12 collection expressions. Without spread: arrays use <code>NewArrayInit</code>, collections use <code>ListInit</code> with <code>Add</code>. With spread: segments are concatenated via <code>Enumerable.Concat&lt;T&gt;</code> and materialized via <code>Enumerable.ToArray&lt;T&gt;</code> / <code>ToList&lt;T&gt;</code>.</td></tr><tr><td><code>ISpreadOperation</code></td><td><em>(handled within collection expression)</em></td><td>Implemented</td><td>Spread operand emitted directly as an <code>IEnumerable&lt;T&gt;</code> segment.</td></tr></tbody></table><h2 id="string-interpolation" tabindex="-1">String Interpolation <a class="header-anchor" href="#string-interpolation" aria-label="Permalink to “String Interpolation”">​</a></h2><table tabindex="0"><thead><tr><th>IOperation</th><th>Expression Factory</th><th>Status</th><th>Notes</th></tr></thead><tbody><tr><td><code>IInterpolatedStringOperation</code></td><td><code>Expression.Call(string.Concat, ...)</code></td><td>Implemented</td><td>Parts flattened to string expressions, non-string parts wrapped in <code>.ToString()</code>. Format specifiers use <code>ToString(format)</code>. Left-fold reduction via <code>string.Concat(string, string)</code>. Alignment specifiers fall through to <code>EmitUnsupported</code>.</td></tr></tbody></table><h2 id="block-body-operations" tabindex="-1">Block Body Operations <a class="header-anchor" href="#block-body-operations" aria-label="Permalink to “Block Body Operations”">​</a></h2><table tabindex="0"><thead><tr><th>IOperation</th><th>Expression Factory</th><th>Status</th><th>Notes</th></tr></thead><tbody><tr><td><code>IBlockOperation</code></td><td><code>Expression.Block(variables, statements)</code></td><td>Implemented</td><td>Local variable declarations, assignments, returns, expression statements. Requires <code>AllowBlockBody = true</code>.</td></tr><tr><td><code>IReturnOperation</code></td><td><em>(result expression)</em></td><td>Implemented</td><td>Extracts the returned value as the block&#39;s result.</td></tr><tr><td><code>IExpressionStatementOperation</code></td><td><em>(transparent)</em></td><td>Implemented</td><td>Unwraps to inner operation.</td></tr><tr><td><code>ISimpleAssignmentOperation</code></td><td><code>Expression.Assign(target, value)</code></td><td>Implemented</td><td>Standalone assignment in block bodies.</td></tr></tbody></table><h2 id="loop-operations" tabindex="-1">Loop Operations <a class="header-anchor" href="#loop-operations" aria-label="Permalink to “Loop Operations”">​</a></h2><table tabindex="0"><thead><tr><th>IOperation</th><th>Expression Factory</th><th>Status</th><th>Notes</th></tr></thead><tbody><tr><td><code>IForEachLoopOperation</code></td><td><code>Expression.Loop</code> with enumerator pattern</td><td>Implemented</td><td>GetEnumerator/MoveNext/Current pattern. <code>ConvertLoopsToLinq</code> transformer rewrites to LINQ for providers that cannot handle <code>LoopExpression</code>.</td></tr><tr><td><code>IForLoopOperation</code></td><td><code>Expression.Loop</code> with init/condition/increment</td><td>Implemented</td><td></td></tr><tr><td><code>IWhileLoopOperation</code></td><td><code>Expression.Loop</code> with condition</td><td>Implemented</td><td>Supports both while (condition-at-top) and do-while (condition-at-bottom).</td></tr></tbody></table><h2 id="nested-lambda-and-delegate-operations" tabindex="-1">Nested Lambda and Delegate Operations <a class="header-anchor" href="#nested-lambda-and-delegate-operations" aria-label="Permalink to “Nested Lambda and Delegate Operations”">​</a></h2><table tabindex="0"><thead><tr><th>IOperation</th><th>Expression Factory</th><th>Status</th><th>Notes</th></tr></thead><tbody><tr><td><code>IAnonymousFunctionOperation</code></td><td><code>Expression.Lambda&lt;TDelegate&gt;(body, params)</code></td><td>Implemented</td><td>Nested lambdas with scoped parameters.</td></tr><tr><td><code>IDelegateCreationOperation</code></td><td><em>(transparent)</em></td><td>Implemented</td><td>Emits its <code>Target</code> operation directly.</td></tr></tbody></table><hr><h2 id="not-yet-implemented" tabindex="-1">Not Yet Implemented <a class="header-anchor" href="#not-yet-implemented" aria-label="Permalink to “Not Yet Implemented”">​</a></h2><table tabindex="0"><thead><tr><th>IOperation</th><th>Target Expression Factory</th><th>Notes</th></tr></thead><tbody><tr><td><code>IThrowOperation</code></td><td><code>Expression.Throw(expr, typeof(T))</code></td><td><code>throw</code> expressions. <code>Expression.Throw</code> exists but not all LINQ providers support it. Detected early by block body validation (EXP0006).</td></tr></tbody></table><hr><h2 id="not-applicable-to-expression-trees" tabindex="-1">Not Applicable to Expression Trees <a class="header-anchor" href="#not-applicable-to-expression-trees" aria-label="Permalink to “Not Applicable to Expression Trees”">​</a></h2><p>These operations are rejected early by block body validation (EXP0005/EXP0006) when inside <code>[Expressive(AllowBlockBody = true)]</code> members.</p><table tabindex="0"><thead><tr><th>IOperation</th><th>Reason</th></tr></thead><tbody><tr><td><code>IEventReferenceOperation</code></td><td>Events cannot appear in expression trees</td></tr><tr><td><code>ICoalesceAssignmentOperation</code></td><td><code>??=</code> is an assignment</td></tr><tr><td><code>IAddressOfOperation</code></td><td>Pointers are not supported in expression trees</td></tr><tr><td><code>IDynamicInvocationOperation</code></td><td>Dynamic dispatch has no expression tree equivalent</td></tr><tr><td><code>IDynamicMemberReferenceOperation</code></td><td>Dynamic dispatch has no expression tree equivalent</td></tr><tr><td><code>IDynamicIndexerAccessOperation</code></td><td>Dynamic dispatch has no expression tree equivalent</td></tr><tr><td><code>IDynamicObjectCreationOperation</code></td><td>Dynamic dispatch has no expression tree equivalent</td></tr><tr><td><code>IFunctionPointerInvocationOperation</code></td><td>Function pointers are not supported in expression trees</td></tr><tr><td><code>IAwaitOperation</code></td><td><code>await</code> has no <code>Expression.*</code> equivalent</td></tr><tr><td><code>IDeconstructionAssignmentOperation</code></td><td><code>(a, b) = ...</code> is a destructuring assignment</td></tr><tr><td><code>ITryOperation</code></td><td>try/catch/finally has no expression tree equivalent</td></tr><tr><td><code>IUsingOperation</code></td><td>using/dispose pattern not representable</td></tr><tr><td><code>ILockOperation</code></td><td>lock has no expression tree equivalent</td></tr></tbody></table><hr><h2 id="limitations-and-known-issues" tabindex="-1">Limitations and Known Issues <a class="header-anchor" href="#limitations-and-known-issues" aria-label="Permalink to “Limitations and Known Issues”">​</a></h2><h3 id="_1-no-explicit-nullable-lifting" tabindex="-1">1. No Explicit Nullable Lifting <a class="header-anchor" href="#_1-no-explicit-nullable-lifting" aria-label="Permalink to “1. No Explicit Nullable Lifting”">​</a></h3><p>The <code>liftToNull</code> parameter in <code>Expression.MakeBinary()</code> is always hardcoded to <code>false</code>. The emitter does not inspect <code>IBinaryOperation.IsLifted</code>. In practice, the .NET expression tree runtime infers lifting from operand types, so this works for standard operators. It may produce incorrect behavior for user-defined operators on nullable types where <code>liftToNull</code> semantics differ.</p><h3 id="_2-ioperation-null-fallback" tabindex="-1">2. IOperation Null Fallback <a class="header-anchor" href="#_2-ioperation-null-fallback" aria-label="Permalink to “2. IOperation Null Fallback”">​</a></h3><p>If <code>SemanticModel.GetOperation()</code> returns <code>null</code> for the body syntax (after unwrapping transparent syntax), the emitter reports <code>EXP0008</code> and produces <code>Expression.Default(typeof(ReturnType))</code> as the lambda body.</p>',56)])])}const b=t(a,[["render",n]]);export{m as __pageData,b as default};
